"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export const DATA_PANEL_CARD_CLASS_NAME = "overflow-hidden rounded-[1.35rem] border border-border/70 bg-card/95 shadow-[0_1px_0_rgba(255,255,255,0.65),0_18px_48px_-32px_rgba(15,23,42,0.28)]"
export const DATA_PANEL_HEADER_CLASS_NAME = "border-b border-border/60 bg-[linear-gradient(180deg,color-mix(in_srgb,var(--background)_84%,var(--muted))_0%,color-mix(in_srgb,var(--background)_96%,transparent)_100%)] px-5 py-4 md:px-6"
export const DATA_PANEL_CONTENT_CLASS_NAME = "px-5 py-5 md:px-6 md:py-6"
export const DATA_PANEL_SECTION_CLASS_NAME = "rounded-[1.1rem] border border-border/60 bg-muted/[0.16] shadow-[inset_0_1px_0_rgba(255,255,255,0.4)]"
export const DATA_TOOLBAR_CARD_CLASS_NAME = "rounded-[1.25rem] border border-border/70 bg-card/90 px-4 py-4 shadow-[0_1px_0_rgba(255,255,255,0.55),0_16px_38px_-34px_rgba(15,23,42,0.35)]"
export const DATA_TABLE_FRAME_CLASS_NAME = "overflow-hidden rounded-[1.25rem] border border-border/70 bg-background/95 shadow-[0_1px_0_rgba(255,255,255,0.52),0_20px_45px_-40px_rgba(15,23,42,0.4)]"
export const DATA_FLOATING_BAR_CLASS_NAME = "rounded-full border border-border/70 bg-background/85 px-5 py-2.5 shadow-[0_18px_50px_-28px_rgba(15,23,42,0.45)] backdrop-blur-md supports-[backdrop-filter]:bg-background/78"
export const DATA_INPUT_CLASS_NAME = "rounded-xl border border-border/70 bg-background/90 shadow-[0_1px_0_rgba(255,255,255,0.45)] transition-colors hover:border-border focus-visible:border-ring"
export const DATA_SUBTLE_ACTION_CLASS_NAME = "rounded-xl border border-border/60 bg-background/80 text-muted-foreground transition-colors hover:border-border hover:bg-muted/40 hover:text-foreground"
export const DATA_DIVIDER_CLASS_NAME = "bg-border/60"

type DataStateTone = "neutral" | "danger" | "success"

export function dataWorkspaceStateClassName(tone: DataStateTone = "neutral"): string {
  if (tone === "danger") {
    return "rounded-[1rem] border border-destructive/25 bg-destructive/10 px-4 py-4 text-sm text-destructive shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
  }

  if (tone === "success") {
    return "rounded-[1rem] border border-emerald-500/20 bg-emerald-500/10 px-4 py-4 text-sm text-emerald-700 shadow-[inset_0_1px_0_rgba(255,255,255,0.3)] dark:text-emerald-300"
  }

  return "rounded-[1rem] border border-dashed border-border/70 bg-muted/[0.2] px-4 py-6 text-sm text-muted-foreground shadow-[inset_0_1px_0_rgba(255,255,255,0.3)]"
}

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-border/50 transition-colors duration-150",
    options?.interactive && "cursor-pointer hover:bg-muted/[0.26]",
    options?.selected && "bg-foreground/[0.05] hover:bg-foreground/[0.07]",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between", className)}>
      <div className="min-w-0 space-y-3">
        <div className="space-y-1.5">
          {eyebrow ? (
            <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-muted-foreground/90">
              {eyebrow}
            </div>
          ) : null}
          <div className="text-lg font-semibold leading-tight tracking-[-0.01em] text-foreground md:text-xl">
            {title}
          </div>
          {description ? (
            <div className="max-w-3xl text-sm leading-6 text-muted-foreground">
              {description}
            </div>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div className={cn(dataWorkspaceStateClassName(tone), className)} {...props}>
      <div className="grid gap-1.5">
        {heading ? (
          <div className="text-sm font-medium text-foreground">
            {heading}
          </div>
        ) : null}
        <div className={cn("leading-6", tone === "neutral" ? "text-muted-foreground" : undefined)}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import {
  DATA_FLOATING_BAR_CLASS_NAME,
  DATA_SUBTLE_ACTION_CLASS_NAME,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
} from "@/components/lemma/registry-data-workspace"

export interface BulkAction {
  label: string
  onClick: (selectedIds: string[]) => void
  variant?: "default" | "destructive"
  isLoading?: boolean
}

export interface LemmaBulkActionsBarProps extends React.HTMLAttributes<HTMLDivElement> {
  selectedCount: number
  selectedIds?: string[]
  title?: string
  description?: string
  isDeleting?: boolean
  isProcessing?: boolean
  deleteLabel?: string
  clearLabel?: string
  onDeleteSelected?: () => void
  onClearSelection?: () => void
  error?: Error | null
  message?: string | null
  actions?: BulkAction[]
}

export const LemmaBulkActionsBar = React.forwardRef<HTMLDivElement, LemmaBulkActionsBarProps>(
  ({
    selectedCount,
    selectedIds = [],
    title = "Bulk actions",
    description = "Select multiple rows to run a single action across them.",
    isDeleting = false,
    isProcessing,
    deleteLabel = "Delete selected",
    clearLabel = "Clear selection",
    onDeleteSelected,
    onClearSelection,
    error,
    message,
    actions = [],
    className,
    ...props
  }, ref) => {
  const isBusy = isDeleting || isProcessing
  if (selectedCount <= 0 && !error && !message) return null

  return (
    <div ref={ref} className={cn("grid gap-3", className)} {...props}>
      {selectedCount > 0 ? (
        <div className={cn("flex flex-col gap-3 md:flex-row md:items-center md:justify-between", DATA_FLOATING_BAR_CLASS_NAME)}>
          <div className="grid gap-1">
            <div className="flex flex-wrap items-center gap-2">
              <div className="text-sm font-medium text-foreground">{title}</div>
              <div className={cn("inline-flex items-center rounded-full border px-2.5 py-0.5 text-[11px] font-medium uppercase tracking-[0.14em]", dataWorkspaceMetaBadgeClassName("primary"))}>
                {selectedCount} selected
              </div>
            </div>
            <div className="text-sm text-muted-foreground">
              {description}
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            {onClearSelection ? (
              <Button className={DATA_SUBTLE_ACTION_CLASS_NAME} onClick={onClearSelection} variant="ghost">
                {clearLabel}
              </Button>
            ) : null}
            {actions.map((action) => (
              <Button
                className={action.variant === "destructive" ? "" : DATA_SUBTLE_ACTION_CLASS_NAME}
                disabled={action.isLoading || isBusy}
                key={action.label}
                onClick={() => action.onClick(selectedIds)}
                variant={action.variant === "destructive" ? "destructive" : "ghost"}
              >
                {action.isLoading ? "Loading…" : action.label}
              </Button>
            ))}
            {onDeleteSelected ? (
              <Button disabled={isBusy} onClick={onDeleteSelected} type="button" variant="destructive">
                {isBusy ? "Deleting…" : deleteLabel}
              </Button>
            ) : null}
          </div>
        </div>
      ) : null}

      {error ? (
        <DataWorkspaceState
          description={error.message}
          tone="danger"
        />
      ) : null}

      {message ? (
        <DataWorkspaceState
          description={message}
          heading={selectedCount > 0 ? `${selectedCount} record${selectedCount === 1 ? "" : "s"} selected.` : title}
        />
      ) : null}
    </div>
  )
})
LemmaBulkActionsBar.displayName = "LemmaBulkActionsBar"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecord } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import { cn } from "@/lib/utils"

type LemmaRecordDetailsVariant = "card" | "sheet"
type LemmaRecordDetailsSide = "top" | "right" | "bottom" | "left"

export interface LemmaRecordDetailsCardProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  fields?: string[]
  title?: string
  description?: string
  variant?: LemmaRecordDetailsVariant
  side?: LemmaRecordDetailsSide
  open?: boolean
  onOpenChange?: (open: boolean) => void
}

function sentenceCase(value: string): string {
  return value
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaRecordDetailsCard = React.forwardRef<HTMLDivElement, LemmaRecordDetailsCardProps>(
  ({
    client,
    podId,
    tableName,
    recordId,
    fields,
    title,
    description,
    variant = "card",
    side = "right",
    open,
    onOpenChange,
    className,
    ...props
  }, ref) => {
    const trimmedTableName = tableName.trim()
    const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
    const recordKey = `${trimmedTableName}:${trimmedRecordId}`
    const [dismissedRecordKey, setDismissedRecordKey] = React.useState<string | null>(null)
    const recordState = useRecord({
      client,
      podId,
      tableName: trimmedTableName,
      recordId: trimmedRecordId || null,
      enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
    })

    const visibleFields = React.useMemo(() => {
      const record = recordState.record
      if (!record) return fields ?? []
      if (fields?.length) return fields
      return Object.keys(record)
        .filter((field) => field !== "created_at" && field !== "updated_at")
        .slice(0, 12)
    }, [fields, recordState.record])

    React.useEffect(() => {
      setDismissedRecordKey(null)
    }, [recordKey])

    const resolvedOpen = variant === "sheet"
      ? typeof open === "boolean"
        ? open
        : trimmedRecordId.length > 0 && dismissedRecordKey !== recordKey
      : false

    const handleOpenChange = React.useCallback((nextOpen: boolean) => {
      if (!nextOpen && typeof open !== "boolean") {
        setDismissedRecordKey(recordKey)
      }
      onOpenChange?.(nextOpen)
    }, [onOpenChange, open, recordKey])

    const headerTitle = title ?? "Record Details"
    const headerDescription = description ?? "Inspect the selected record with real values."
    const metaSummary = (
      <div className="flex flex-wrap items-center gap-2">
        <Badge variant="secondary">{trimmedTableName}</Badge>
        <Badge variant="outline">{visibleFields.length} field{visibleFields.length === 1 ? "" : "s"}</Badge>
        <Badge variant="outline" className="max-w-full truncate font-mono text-[11px]">
          {trimmedRecordId}
        </Badge>
      </div>
    )

    const detailsBody = (
      <div ref={ref} className={cn("flex min-h-0 flex-1 flex-col", className)} {...props}>
        <div className="flex items-start justify-between gap-3 border-b border-border px-6 py-5">
          <div className="grid gap-3">
            <div className="grid gap-1">
              <h3 className="text-lg font-semibold text-foreground">{headerTitle}</h3>
              <p className="text-sm text-muted-foreground">{headerDescription}</p>
            </div>
            {metaSummary}
          </div>
          <Button
            disabled={recordState.isLoading}
            onClick={() => {
              void recordState.refresh()
            }}
            type="button"
            variant="outline"
          >
            {recordState.isLoading ? "Refreshing..." : "Refresh"}
          </Button>
        </div>

        <div className="min-h-0 flex-1 overflow-y-auto px-6 py-6">
          <div className="grid gap-4">
            {recordState.error ? (
              <div className="rounded-xl border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
                {recordState.error.message}
              </div>
            ) : null}

            {recordState.isLoading && !recordState.record ? (
              <div className="rounded-xl border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
                Loading record details...
              </div>
            ) : null}

            {recordState.record ? (
              <div className="grid gap-3 md:grid-cols-2">
                {visibleFields.map((field) => (
                  <section
                    key={field}
                    className="grid gap-3 rounded-xl border border-border/70 bg-muted/20 p-4 shadow-sm"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="text-sm font-medium text-foreground">{sentenceCase(field)}</div>
                      <Badge variant="outline" className="font-mono text-[10px] uppercase tracking-wide">
                        {field}
                      </Badge>
                    </div>
                    <pre className="overflow-x-auto whitespace-pre-wrap break-words text-sm leading-6 text-muted-foreground">
                      {formatValue(recordState.record?.[field])}
                    </pre>
                  </section>
                ))}
              </div>
            ) : null}
          </div>
        </div>
      </div>
    )

    if (!trimmedTableName || !trimmedRecordId) {
      if (variant === "sheet") {
        return null
      }

      return (
        <Card ref={ref} className={cn("", className)} {...props}>
          <CardHeader>
            <CardTitle>{headerTitle}</CardTitle>
            <CardDescription>{description ?? "Select a record to inspect its full payload."}</CardDescription>
          </CardHeader>
        </Card>
      )
    }

    if (variant === "sheet") {
      return (
        <Sheet open={resolvedOpen} onOpenChange={handleOpenChange}>
          <SheetContent className="flex w-full flex-col gap-0 sm:max-w-2xl" side={side}>
            <SheetHeader className="sr-only">
              <SheetTitle>{headerTitle}</SheetTitle>
              <SheetDescription>{headerDescription}</SheetDescription>
            </SheetHeader>
            {detailsBody}
          </SheetContent>
        </Sheet>
      )
    }

    return (
      <Card ref={ref} className={cn("overflow-hidden border-border/70 shadow-sm", className)} {...props}>
        <CardHeader>
          <div className="flex items-start justify-between gap-3">
            <div className="grid gap-3">
              <div className="grid gap-1">
                <CardTitle>{headerTitle}</CardTitle>
                <CardDescription>{headerDescription}</CardDescription>
              </div>
              {metaSummary}
            </div>
            <Button
              disabled={recordState.isLoading}
              onClick={() => {
                void recordState.refresh()
              }}
              type="button"
              variant="outline"
            >
              {recordState.isLoading ? "Refreshing..." : "Refresh"}
            </Button>
          </div>
        </CardHeader>
        <CardContent className="grid gap-4">
          {recordState.error ? (
            <div className="rounded-xl border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {recordState.error.message}
            </div>
          ) : null}

          {recordState.isLoading && !recordState.record ? (
            <div className="rounded-xl border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
              Loading record details...
            </div>
          ) : null}

          {recordState.record ? (
            <div className="grid gap-3 md:grid-cols-2">
              {visibleFields.map((field) => (
                <section
                  key={field}
                  className="grid gap-3 rounded-xl border border-border/70 bg-muted/20 p-4 shadow-sm"
                >
                  <div className="flex items-center justify-between gap-3">
                    <div className="text-sm font-medium text-foreground">{sentenceCase(field)}</div>
                    <Badge variant="outline" className="font-mono text-[10px] uppercase tracking-wide">
                      {field}
                    </Badge>
                  </div>
                  <pre className="overflow-x-auto whitespace-pre-wrap break-words text-sm leading-6 text-muted-foreground">
                    {formatValue(recordState.record?.[field])}
                  </pre>
                </section>
              ))}
            </div>
          ) : null}
        </CardContent>
      </Card>
    )
  },
)
LemmaRecordDetailsCard.displayName = "LemmaRecordDetailsCard"

"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { cn } from "@/lib/utils"
import {
  DATA_INPUT_CLASS_NAME,
  DATA_PANEL_SECTION_CLASS_NAME,
  DATA_SUBTLE_ACTION_CLASS_NAME,
  DATA_TOOLBAR_CARD_CLASS_NAME,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
} from "@/components/lemma/registry-data-workspace"

type SortFieldOption = string | { value: string; label: string }
export type LemmaFilterFieldType =
  | "text"
  | "textarea"
  | "number"
  | "boolean"
  | "json"
  | "date"
  | "datetime"
  | "select"
  | "foreign-key"
  | "uuid"
  | (string & {})

export interface LemmaFilterFieldOption {
  value: string
  label: string
  type?: LemmaFilterFieldType
  options?: string[]
}

export type LemmaFilterOperator =
  | "contains"
  | "does_not_contain"
  | "is"
  | "is_not"
  | "starts_with"
  | "ends_with"
  | "gt"
  | "gte"
  | "lt"
  | "lte"
  | "is_empty"
  | "is_not_empty"

export interface LemmaFilterCondition {
  id: string
  field: string
  op: LemmaFilterOperator
  value?: string | number | boolean
}

export interface LemmaRecordFiltersBarProps extends React.HTMLAttributes<HTMLDivElement> {
  search: string
  onSearchChange: (value: string) => void
  searchPlaceholder?: string
  resultCount?: number
  onRefresh?: () => void
  isRefreshing?: boolean
  sortBy?: string
  onSortByChange?: (value: string) => void
  sortOrder?: "asc" | "desc"
  onSortOrderChange?: (value: "asc" | "desc") => void
  availableSortFields?: SortFieldOption[]
  pageSize?: number
  onPageSizeChange?: (value: number) => void
  pageSizeOptions?: number[]
  availableFilterFields?: LemmaFilterFieldOption[]
  filters?: LemmaFilterCondition[]
  onFiltersChange?: (filters: LemmaFilterCondition[]) => void
  allowSearch?: boolean
  allowFilters?: boolean
  allowSorting?: boolean
  allowPageSizeSelect?: boolean
}

const DEFAULT_PAGE_SIZE_OPTIONS = [10, 25, 50, 100]
const DEFAULT_SORT_VALUE = "__default__"
const FILTERABLE_TEXT_TYPES = new Set(["text", "textarea", "uuid", "foreign-key", "json"])
const FILTERABLE_NUMERIC_TYPES = new Set(["number"])
const FILTERABLE_TEMPORAL_TYPES = new Set(["date", "datetime"])

function createEmptyFilter(field?: LemmaFilterFieldOption): LemmaFilterCondition {
  return {
    id: Math.random().toString(36).slice(2, 10),
    field: field?.value ?? "",
    op: defaultFilterOperator(field?.type),
    value: "",
  }
}

function normalizeSortOptions(options?: SortFieldOption[]): Array<{ value: string; label: string }> {
  if (!options?.length) return []

  return options
    .map((option) => (
      typeof option === "string"
        ? { value: option, label: option }
        : option
    ))
    .filter((option) => option.value.trim().length > 0)
}

function defaultFilterOperator(type?: LemmaFilterFieldType): LemmaFilterOperator {
  if (type === "boolean") return "is"
  if (type === "select") return "is"
  if (FILTERABLE_NUMERIC_TYPES.has(type ?? "")) return "is"
  if (FILTERABLE_TEMPORAL_TYPES.has(type ?? "")) return "is"
  return "contains"
}

function availableOperators(type?: LemmaFilterFieldType): Array<{ value: LemmaFilterOperator; label: string }> {
  if (type === "boolean" || type === "select") {
    return [
      { value: "is", label: "is" },
      { value: "is_not", label: "is not" },
    ]
  }

  if (FILTERABLE_NUMERIC_TYPES.has(type ?? "") || FILTERABLE_TEMPORAL_TYPES.has(type ?? "")) {
    return [
      { value: "is", label: "is" },
      { value: "is_not", label: "is not" },
      { value: "gt", label: "greater than" },
      { value: "gte", label: "greater or equal" },
      { value: "lt", label: "less than" },
      { value: "lte", label: "less or equal" },
      { value: "is_empty", label: "is empty" },
      { value: "is_not_empty", label: "is not empty" },
    ]
  }

  return [
    { value: "contains", label: "contains" },
    { value: "does_not_contain", label: "does not contain" },
    { value: "is", label: "is" },
    { value: "is_not", label: "is not" },
    { value: "starts_with", label: "starts with" },
    { value: "ends_with", label: "ends with" },
    { value: "is_empty", label: "is empty" },
    { value: "is_not_empty", label: "is not empty" },
  ]
}

function operatorNeedsValue(op: LemmaFilterOperator): boolean {
  return op !== "is_empty" && op !== "is_not_empty"
}

function stringifyFilterValue(value: LemmaFilterCondition["value"]): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  return ""
}

export const LemmaRecordFiltersBar = React.forwardRef<HTMLDivElement, LemmaRecordFiltersBarProps>(
  ({
    search,
    onSearchChange,
    searchPlaceholder = "Search records…",
    resultCount,
    onRefresh,
    isRefreshing = false,
    sortBy = "",
    onSortByChange,
    sortOrder = "asc",
    onSortOrderChange,
    availableSortFields,
    pageSize,
    onPageSizeChange,
    pageSizeOptions = DEFAULT_PAGE_SIZE_OPTIONS,
    availableFilterFields = [],
    filters = [],
    onFiltersChange,
    allowSearch = true,
    allowFilters = true,
    allowSorting = true,
    allowPageSizeSelect = true,
    className,
    ...props
  }, ref) => {
  const sortOptions = React.useMemo(
    () => normalizeSortOptions(availableSortFields),
    [availableSortFields],
  )
  const [isFilterEditorOpen, setIsFilterEditorOpen] = React.useState(false)
  const [draftFilters, setDraftFilters] = React.useState<LemmaFilterCondition[]>(filters)

  React.useEffect(() => {
    if (!isFilterEditorOpen) {
      setDraftFilters(filters)
    }
  }, [filters, isFilterEditorOpen])

  const activeFilterCount = filters.filter((filter) => (
    filter.field
    && (operatorNeedsValue(filter.op) ? stringifyFilterValue(filter.value).trim().length > 0 : true)
  )).length
  const firstFilterField = availableFilterFields[0]

  return (
    <div ref={ref} className={cn("", className)} {...props}>
    <div className={cn("flex min-w-0 flex-col gap-4", DATA_TOOLBAR_CARD_CLASS_NAME)}>
      <div className="flex min-w-0 flex-col gap-3 xl:flex-row xl:items-center">
      {allowSearch ? (
        <div className="min-w-[240px] flex-1">
          <Input
            className={DATA_INPUT_CLASS_NAME}
            onChange={(event) => onSearchChange(event.target.value)}
            placeholder={searchPlaceholder}
            value={search}
          />
        </div>
      ) : null}
      {allowFilters && onFiltersChange && availableFilterFields.length > 0 ? (
        <Button
          className={DATA_SUBTLE_ACTION_CLASS_NAME}
          onClick={() => {
            setDraftFilters(filters.length > 0 ? filters : [createEmptyFilter(firstFilterField)])
            setIsFilterEditorOpen(true)
          }}
          type="button"
          variant="ghost"
        >
          Filters{activeFilterCount > 0 ? ` (${activeFilterCount})` : ""}
        </Button>
      ) : null}
      {allowSorting && sortOptions.length > 0 && onSortByChange ? (
        <div className="grid gap-2 md:min-w-[180px]">
          <Select
            value={sortBy || DEFAULT_SORT_VALUE}
            onValueChange={(value) => onSortByChange(value === DEFAULT_SORT_VALUE ? "" : value)}
          >
            <SelectTrigger className={DATA_INPUT_CLASS_NAME} id="lemma-record-filters-sort-by">
              <SelectValue placeholder="Sort field" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={DEFAULT_SORT_VALUE}>Default order</SelectItem>
              {sortOptions.map((option) => (
                <SelectItem key={option.value} value={option.value}>
                  {option.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      ) : null}
      {allowSorting && onSortOrderChange ? (
        <div className="grid gap-2 md:min-w-[140px]">
          <Select value={sortOrder} onValueChange={(value) => onSortOrderChange(value as "asc" | "desc")}>
            <SelectTrigger className={DATA_INPUT_CLASS_NAME} id="lemma-record-filters-sort-order">
              <SelectValue placeholder="Sort order" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="asc">Ascending</SelectItem>
              <SelectItem value="desc">Descending</SelectItem>
            </SelectContent>
          </Select>
        </div>
      ) : null}
      {allowPageSizeSelect && typeof pageSize === "number" && onPageSizeChange ? (
        <div className="grid gap-2 md:min-w-[130px]">
          <Select value={String(pageSize)} onValueChange={(value) => onPageSizeChange(Number(value))}>
            <SelectTrigger className={DATA_INPUT_CLASS_NAME} id="lemma-record-filters-page-size">
              <SelectValue placeholder="Page size" />
            </SelectTrigger>
            <SelectContent>
              {pageSizeOptions.map((option) => (
                <SelectItem key={option} value={String(option)}>
                  {option} / page
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      ) : null}
      <div className="flex flex-wrap items-center gap-3 xl:ml-auto">
        {typeof resultCount === "number" ? (
          <p className={cn("inline-flex items-center rounded-full border px-2.5 py-1 text-xs font-medium", dataWorkspaceMetaBadgeClassName("default"))}>
            {resultCount} result{resultCount === 1 ? "" : "s"}
          </p>
        ) : null}
        {onRefresh ? (
          <Button className={DATA_SUBTLE_ACTION_CLASS_NAME} disabled={isRefreshing} onClick={onRefresh} type="button" variant="ghost">
            {isRefreshing ? "Refreshing…" : "Refresh"}
          </Button>
        ) : null}
      </div>
      </div>
      {activeFilterCount > 0 ? (
        <div className="flex flex-wrap gap-2">
          {filters
            .filter((filter) => (
              filter.field
              && (operatorNeedsValue(filter.op) ? stringifyFilterValue(filter.value).trim().length > 0 : true)
            ))
            .map((filter) => {
              const field = availableFilterFields.find((option) => option.value === filter.field)
              const operator = availableOperators(field?.type).find((option) => option.value === filter.op)
              return (
                <div
                  className={cn("inline-flex items-center gap-2 rounded-full border px-3 py-1 text-xs", dataWorkspaceMetaBadgeClassName("default"))}
                  key={filter.id}
                >
                  <span className="font-medium text-foreground">{field?.label ?? filter.field}</span>
                  <span>{operator?.label ?? filter.op}</span>
                  {operatorNeedsValue(filter.op) ? <span>{filter.value}</span> : null}
                </div>
              )
            })}
        </div>
      ) : null}

      {!activeFilterCount && !search.trim() && !sortBy && typeof resultCount !== "undefined" ? (
        <DataWorkspaceState
          description="Search, sort, and filters stay compact until you need them, then expand into a dedicated editor."
          heading="Operational controls"
        />
      ) : null}
    </div>
    <Sheet open={isFilterEditorOpen} onOpenChange={setIsFilterEditorOpen}>
      <SheetContent className="flex w-full flex-col gap-0 border-l border-border/70 bg-background/95 p-0 sm:max-w-4xl" side="right">
        <SheetHeader className="border-b border-border/60 px-6 py-5 text-left">
          <SheetTitle>Filter Records</SheetTitle>
          <SheetDescription>
            Refine the current records view with structured conditions.
          </SheetDescription>
        </SheetHeader>
        <div className="grid gap-4 border-b border-border/60 px-6 py-6">
            {draftFilters.map((filter, index) => {
              const field = availableFilterFields.find((option) => option.value === filter.field) ?? firstFilterField
              const operators = availableOperators(field?.type)
              const showValueInput = operatorNeedsValue(filter.op)
              const fieldType = field?.type ?? "text"
              return (
                <div className={cn("grid gap-3 p-4 md:grid-cols-[minmax(0,1.3fr)_minmax(180px,0.9fr)_minmax(0,1.6fr)_auto]", DATA_PANEL_SECTION_CLASS_NAME)} key={filter.id}>
                  <Select
                    value={filter.field}
                    onValueChange={(value) => {
                      const nextField = availableFilterFields.find((option) => option.value === value)
                      setDraftFilters((current) => current.map((entry) => (
                        entry.id === filter.id
                          ? {
                              ...entry,
                              field: value,
                              op: defaultFilterOperator(nextField?.type),
                              value: "",
                            }
                          : entry
                      )))
                    }}
                  >
                    <SelectTrigger className={DATA_INPUT_CLASS_NAME}>
                      <SelectValue placeholder="Field" />
                    </SelectTrigger>
                    <SelectContent>
                      {availableFilterFields.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Select
                    value={filter.op}
                    onValueChange={(value) => {
                      const opValue = value as LemmaFilterOperator
                      setDraftFilters((current) => current.map((entry) => (
                        entry.id === filter.id
                          ? {
                              ...entry,
                              op: opValue,
                              value: operatorNeedsValue(opValue) ? entry.value ?? "" : "",
                            }
                          : entry
                      )))
                    }}
                  >
                    <SelectTrigger className={DATA_INPUT_CLASS_NAME}>
                      <SelectValue placeholder="Condition" />
                    </SelectTrigger>
                    <SelectContent>
                      {operators.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {showValueInput ? (
                    fieldType === "boolean" ? (
                      <Select
                        value={stringifyFilterValue(filter.value)}
                        onValueChange={(value) => {
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                      >
                        <SelectTrigger className={DATA_INPUT_CLASS_NAME}>
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="true">True</SelectItem>
                          <SelectItem value="false">False</SelectItem>
                        </SelectContent>
                      </Select>
                    ) : fieldType === "select" && field?.options?.length ? (
                      <Select
                        value={stringifyFilterValue(filter.value)}
                        onValueChange={(value) => {
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                      >
                        <SelectTrigger className={DATA_INPUT_CLASS_NAME}>
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          {field.options.map((option) => (
                            <SelectItem key={option} value={option}>
                              {option}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    ) : (
                      <Input
                        className={DATA_INPUT_CLASS_NAME}
                        onChange={(event) => {
                          const value = event.target.value
                          setDraftFilters((current) => current.map((entry) => (
                            entry.id === filter.id ? { ...entry, value } : entry
                          )))
                        }}
                        placeholder="Value"
                        type={fieldType === "number" ? "number" : fieldType === "date" ? "date" : fieldType === "datetime" ? "datetime-local" : "text"}
                        value={stringifyFilterValue(filter.value)}
                      />
                    )
                  ) : (
                    <div className="flex items-center rounded-xl border border-dashed border-border/70 bg-muted/[0.18] px-4 py-3 text-sm text-muted-foreground">
                      No value needed
                    </div>
                  )}
                  <Button
                    className={DATA_SUBTLE_ACTION_CLASS_NAME}
                    onClick={() => {
                      setDraftFilters((current) => current.filter((entry) => entry.id !== filter.id))
                    }}
                    type="button"
                    variant="ghost"
                  >
                    Remove
                  </Button>
                </div>
              )
            })}
            <button
              className="flex w-full items-center justify-center gap-2 rounded-[1rem] border border-dashed border-border/70 bg-muted/[0.12] px-4 py-4 text-base font-medium text-muted-foreground transition-colors hover:bg-muted/[0.22] hover:text-foreground"
              onClick={() => {
                setDraftFilters((current) => [...current, createEmptyFilter(firstFilterField)])
              }}
              type="button"
            >
              <span className="text-xl leading-none">+</span>
              Add Condition
            </button>
        </div>
        <SheetFooter className="border-t border-border/60 px-6 py-5">
          <Button
            className={DATA_SUBTLE_ACTION_CLASS_NAME}
            onClick={() => {
              setDraftFilters(filters)
              setIsFilterEditorOpen(false)
            }}
            type="button"
            variant="ghost"
          >
            Cancel
          </Button>
          <Button
            onClick={() => {
              onFiltersChange?.(
                draftFilters.filter((filter) => (
                  filter.field.trim().length > 0
                  && (operatorNeedsValue(filter.op) ? stringifyFilterValue(filter.value).trim().length > 0 : true)
                )),
              )
              setIsFilterEditorOpen(false)
            }}
            type="button"
          >
            Apply Filters
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
    </div>
  )
})
LemmaRecordFiltersBar.displayName = "LemmaRecordFiltersBar"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecordForm } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import { Textarea } from "@/components/ui/textarea"
import { LemmaForeignKeySelect } from "@/components/lemma/lemma-foreign-key-select"
import { cn } from "@/lib/utils"

type LemmaRecordFormVariant = "card" | "sheet"
type LemmaRecordFormSide = "top" | "right" | "bottom" | "left"

export interface LemmaRecordFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  initialValues?: Record<string, unknown>
  mode?: "auto" | "create" | "update"
  title?: string
  description?: string
  submitLabel?: string
  hiddenFields?: string[]
  fieldOrder?: string[]
  onSubmitted?: (record: Record<string, unknown>) => void
  onCancel?: () => void
  appearance?: "card" | "modal"
  variant?: LemmaRecordFormVariant
  side?: LemmaRecordFormSide
  open?: boolean
  onOpenChange?: (open: boolean) => void
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
  showReset?: boolean
  resetLabel?: string
  cancelLabel?: string
  onError?: (error: Error) => void
}

function orderFields(
  fields: Array<ReturnType<typeof useRecordForm>["editableFields"][number]>,
  fieldOrder?: string[],
) {
  if (!fieldOrder?.length) return fields

  const indexByName = new Map(fieldOrder.map((name, index) => [name, index]))

  return [...fields].sort((left, right) => {
    const leftIndex = indexByName.get(left.name)
    const rightIndex = indexByName.get(right.name)

    if (typeof leftIndex === "number" && typeof rightIndex === "number") {
      return leftIndex - rightIndex
    }

    if (typeof leftIndex === "number") return -1
    if (typeof rightIndex === "number") return 1
    return left.label.localeCompare(right.label)
  })
}

function defaultFieldLabel(name: string): string {
  return name.replace(/\./g, "_").toUpperCase()
}

function fieldTypeBadgeClassName(kind: string): string {
  if (kind === "select") return "border-orange-200 bg-orange-50 text-orange-700"
  if (kind === "foreign-key" || kind === "uuid") return "border-sky-200 bg-sky-50 text-sky-700"
  if (kind === "boolean") return "border-emerald-200 bg-emerald-50 text-emerald-700"
  if (kind === "date" || kind === "datetime") return "border-violet-200 bg-violet-50 text-violet-700"
  return "border-blue-200 bg-blue-50 text-blue-700"
}

function buildPlaceholder(label: string, kind: string): string {
  if (kind === "select") return `Select ${label.toLowerCase()}`
  if (kind === "foreign-key") return `Choose ${label.toLowerCase()}`
  return `Enter ${label.toLowerCase()}...`
}

export const LemmaRecordForm = React.forwardRef<HTMLDivElement, LemmaRecordFormProps>(
  ({
    client,
    podId,
    tableName,
    recordId,
    initialValues,
    mode = "auto",
    title,
    description,
    submitLabel = recordId ? "Save changes" : "Create record",
    hiddenFields = [],
    fieldOrder,
    onSubmitted,
    onCancel,
    appearance = "card",
    variant,
    side = "right",
    open,
    onOpenChange,
    fieldLabels,
    fieldDescriptions,
    showReset = true,
    resetLabel = "Reset",
    cancelLabel = "Cancel",
    onError,
    className,
    ...props
  }, ref) => {
    const hasTableName = tableName.trim().length > 0
    const formId = React.useId()
    const resolvedVariant = variant ?? (appearance === "modal" ? "sheet" : "card")
    const [internalOpen, setInternalOpen] = React.useState(open ?? true)

    const form = useRecordForm({
      client,
      podId,
      tableName,
      recordId,
      initialValues,
      mode,
      onSubmitSuccess: (record) => onSubmitted?.(record),
    })

    React.useEffect(() => {
      if (form.error) {
        onError?.(form.error)
      }
    }, [form.error, onError])

    React.useEffect(() => {
      if (typeof open === "boolean") {
        setInternalOpen(open)
      }
    }, [open])

    const fields = React.useMemo(() => {
      const visibleFields = form.editableFields.filter((field) => !hiddenFields.includes(field.name))
      return orderFields(visibleFields, fieldOrder)
    }, [fieldOrder, form.editableFields, hiddenFields])

    const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault()
      await form.submit()
    }, [form])

    const handleSheetOpenChange = React.useCallback((nextOpen: boolean) => {
      if (typeof open !== "boolean") {
        setInternalOpen(nextOpen)
      }
      onOpenChange?.(nextOpen)
      if (!nextOpen) {
        onCancel?.()
      }
    }, [onCancel, onOpenChange, open])

    if (!hasTableName) {
      return (
        <Card ref={ref} className={cn("", className)} {...props}>
          <CardHeader>
            <CardTitle>{title ?? "Registry Record Form"}</CardTitle>
            <CardDescription>
              {description ?? "Select a table to render the generated record form."}
            </CardDescription>
          </CardHeader>
        </Card>
      )
    }

    const resolvedTitle = title ?? `${recordId ? "Edit" : "Create"} ${tableName}`
    const resolvedDescription = description ?? "Schema-aware form powered by lemma-sdk/react."
    const meta = (
      <div className="flex flex-wrap items-center gap-2">
        <Badge className="rounded-full px-4 py-1 text-sm font-medium" variant="secondary">
          {recordId ? "Update" : "Create"}
        </Badge>
        <Badge className="rounded-full px-4 py-1 text-sm font-medium" variant="outline">
          {fields.length} field{fields.length === 1 ? "" : "s"}
        </Badge>
        <Badge className="rounded-full px-4 py-1 text-sm font-medium" variant="outline">
          {tableName}
        </Badge>
      </div>
    )

    const body = (
      <form className="flex flex-col gap-5" id={formId} onSubmit={handleSubmit}>
        {form.error ? (
          <div className="rounded-xl border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {form.error.message}
          </div>
        ) : null}

        {form.isLoadingSchema || form.isLoadingRecord ? (
          <div className="rounded-xl border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            Loading form...
          </div>
        ) : null}

        {!form.isLoadingSchema && !form.isLoadingRecord && fields.length === 0 ? (
          <div className="rounded-xl border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            No editable fields were found for this table.
          </div>
        ) : null}

        {fields.map((field) => {
          const value = form.values[field.name]
          const error = form.fieldErrors[field.name]
          const resolvedLabel = fieldLabels?.[field.name] ?? defaultFieldLabel(field.name)
          const resolvedFieldDescription = fieldDescriptions?.[field.name] ?? field.column.description
          const placeholder = buildPlaceholder(resolvedLabel, field.kind)
          const fieldHeader = (
            <div className="flex flex-wrap items-center gap-3">
              <Label
                className="text-[0.8rem] font-semibold tracking-[0.14em] text-muted-foreground"
                htmlFor={field.name}
              >
                {resolvedLabel}
                {field.required ? " *" : ""}
              </Label>
              <Badge
                className={cn(
                  "rounded-md border px-2.5 py-1 text-[0.8rem] font-semibold lowercase tracking-normal",
                  fieldTypeBadgeClassName(field.kind),
                )}
                variant="outline"
              >
                {field.column.type.toLowerCase()}
              </Badge>
            </div>
          )

          if (field.kind === "boolean") {
            return (
              <div key={field.name} className="grid gap-3">
                {fieldHeader}
                {resolvedFieldDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedFieldDescription}</p>
                ) : null}
                <label className="flex items-center gap-3 rounded-xl border border-border/70 bg-background px-4 py-4 text-sm shadow-sm">
                  <Checkbox
                    checked={Boolean(value)}
                    onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                  />
                  <span className="font-medium text-foreground">{Boolean(value) ? "Yes" : "No"}</span>
                </label>
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          }

          if (field.kind === "select") {
            return (
              <div key={field.name} className="grid gap-2">
                {fieldHeader}
                {resolvedFieldDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedFieldDescription}</p>
                ) : null}
                <Select
                  value={typeof value === "string" ? value : ""}
                  onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                >
                  <SelectTrigger className="h-12 w-full rounded-xl border-border/70 bg-background px-4 text-sm shadow-sm" id={field.name}>
                    <SelectValue placeholder={placeholder} />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      {field.options.map((option) => (
                        <SelectItem key={option} value={option}>
                          {option}
                        </SelectItem>
                      ))}
                    </SelectGroup>
                  </SelectContent>
                </Select>
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          }

          if (field.kind === "foreign-key") {
            return (
              <div key={field.name} className="grid gap-2">
                {fieldHeader}
                {resolvedFieldDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedFieldDescription}</p>
                ) : null}
                <LemmaForeignKeySelect
                  client={client}
                  columnName={field.name}
                  onValueChange={(nextValue: string) => form.setValue(field.name, nextValue)}
                  podId={podId}
                  tableName={tableName}
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          }

          if (field.kind === "json" || field.kind === "textarea") {
            return (
              <div key={field.name} className="grid gap-2">
                {fieldHeader}
                {resolvedFieldDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedFieldDescription}</p>
                ) : null}
                <Textarea
                  className="min-h-24 rounded-xl border-border/70 bg-background px-4 py-3 text-sm shadow-sm"
                  id={field.name}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                  placeholder={placeholder}
                  rows={field.kind === "json" ? 6 : 3}
                  value={typeof value === "string" ? value : ""}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          }

          return (
            <div key={field.name} className="grid gap-2">
              {fieldHeader}
              {resolvedFieldDescription ? (
                <p className="text-sm leading-6 text-muted-foreground">{resolvedFieldDescription}</p>
              ) : null}
              <Input
                className="h-12 rounded-xl border-border/70 bg-background px-4 text-sm shadow-sm"
                id={field.name}
                onChange={(event) => form.setValue(field.name, event.target.value)}
                placeholder={placeholder}
                type={
                  field.kind === "number"
                    ? "number"
                    : field.kind === "date"
                      ? "date"
                      : field.kind === "datetime"
                        ? "datetime-local"
                        : "text"
                }
                value={typeof value === "string" ? value : value ? String(value) : ""}
              />
              {error ? <p className="text-sm text-destructive">{error}</p> : null}
            </div>
          )
        })}

        {resolvedVariant === "card" ? (
          <div className="flex flex-wrap items-center justify-end gap-3 border-t border-border pt-6">
            {showReset ? (
              <Button
                className="rounded-xl"
                disabled={form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
